mapper.select:
SELECT ar.id, ar.penalty_id AS penaltyId, ar.user_id AS userId, ar.appeal_reason AS appealReason, ar.evidence, ar.status, ar.review_result AS reviewResult, ar.reviewer_id AS reviewerId, ar.review_time AS reviewTime, ar.review_remark AS reviewRemark, ar.created_at AS createdAt, u.username, pr.penalty_type AS penaltyType, pr.reason AS penaltyReason, au.username AS reviewerName FROM appeal_records ar LEFT JOIN users u ON ar.user_id = u.id LEFT JOIN penalty_records pr ON ar.penalty_id = pr.id LEFT JOIN admin_users au ON ar.reviewer_id = au.id
AND ar.status = #{status}
ORDER BY ar.created_at DESC LIMIT #{offset}, #{limit}
